## 2. Create Accessibility Test Utility
```typescript
// e2e/utils/a11y-testing.ts
import AxeBuilder from '@axe-core/playwright';
import { Page, TestInfo } from '@playwright/test';

export async function checkAccessibility(
  page: Page,
  testInfo: TestInfo,
  options: {
    skipRules?: string[];
    runOnly?: string[];
    include?: string[];
    exclude?: string[];
  } = {}
) {
  const builder = new AxeBuilder({ page });

  if (options.skipRules) {
    builder.disableRules(options.skipRules);
  }
  if (options.runOnly) {
    builder.withRules(options.runOnly);
  }
  if (options.include) {
    builder.include(options.include);
  }
  if (options.exclude) {
    builder.exclude(options.exclude);
  }

  const results = await builder.analyze();

  // Attach results to test report
  await testInfo.attach('accessibility-results', {
    body: JSON.stringify(results, null, 2),
    contentType: 'application/json',
  });

  return results;
}

export function formatViolations(violations: any[]): string {
  return violations.map(v => {
    return `
[${v.impact}] ${v.id}: ${v.description}
  Help: ${v.helpUrl}
  Affected elements:
${v.nodes.map(n => `    - ${n.target.join(' ')}`).join('\n')}
`;
  }).join('\n');
}
```

## 3. Add Accessibility Tests
```typescript
// e2e/accessibility.spec.ts
import { test, expect } from './utils/test-fixtures';
import { checkAccessibility, formatViolations } from './utils/a11y-testing';

test.describe('Accessibility', () => {
  const pages = [
    { path: '/', name: 'Home' },
    { path: '/corpus', name: 'Corpus Index' },
    { path: '/corpus/transcript-batch-1', name: 'Transcript Document' },
    { path: '/method', name: 'Method Reference' },
    { path: '/glossary', name: 'Glossary' },
    { path: '/sessions/new', name: 'Session Creation' },
  ];

  for (const { path, name } of pages) {
    test(`${name} page has no critical accessibility violations`, async ({ page }, testInfo) => {
      await page.goto(path);
      await page.waitForLoadState('networkidle');

      const results = await checkAccessibility(page, testInfo);

      // Filter to critical/serious issues only
      const critical = results.violations.filter(
        v => v.impact === 'critical' || v.impact === 'serious'
      );

      if (critical.length > 0) {
        console.error(formatViolations(critical));
      }

      expect(critical).toHaveLength(0);
    });
  }

  test.describe('Interactive Components', () => {
    test('search modal is keyboard accessible', async ({ page }, testInfo) => {
      await page.goto('/corpus');
      await page.keyboard.press('Meta+k');

      const results = await checkAccessibility(page, testInfo, {
        include: ['[data-testid="spotlight-search"]'],
      });

      expect(results.violations.filter(v => v.impact === 'critical')).toHaveLength(0);
    });

    test('session form has proper labels', async ({ page }, testInfo) => {
      await page.goto('/sessions/new');

      const results = await checkAccessibility(page, testInfo, {
        runOnly: ['label', 'label-title-only', 'form-field-multiple-labels'],
      });

      expect(results.violations).toHaveLength(0);
    });
  });

  test.describe('Color Contrast', () => {
    test('text meets WCAG AA contrast requirements', async ({ page }, testInfo) => {
      await page.goto('/corpus');

      const results = await checkAccessibility(page, testInfo, {
        runOnly: ['color-contrast'],
      });

      expect(results.violations).toHaveLength(0);
    });
  });

  test.describe('Keyboard Navigation', () => {
    test('all interactive elements are keyboard focusable', async ({ page }, testInfo) => {
      await page.goto('/corpus');

      const results = await checkAccessibility(page, testInfo, {
        runOnly: ['tabindex', 'focus-order-semantics'],
      });

      expect(results.violations).toHaveLength(0);
    });
  });
});
```

